-- =========================================================
-- 世界のひとさじ 調味料22件 登録スクリプト
-- 事前準備:
--   1) アプリで「道満調味料研究所」というニックネームのアカウントを作成
--   2) このSQL全体を Supabase の SQL Editor に貼って実行
-- =========================================================
DO $$
DECLARE owner UUID;
BEGIN
  SELECT id INTO owner FROM public.profiles WHERE nickname = '道満調味料研究所' LIMIT 1;
  IF owner IS NULL THEN
    RAISE EXCEPTION 'ニックネーム「道満調味料研究所」のアカウントが見つかりません。先にアプリで登録してください。';
  END IF;

  DELETE FROM public.condiments WHERE user_id = owner;  -- 二重登録防止（任意）

END $$;
